  if (parsed.on_screen_text.length < 2) throw new Error('MISSING_ON_SCREEN_TEXT');

  if (!Array.isArray(parsed.hashtags)) parsed.hashtags = [];
  if (!Array.isArray(parsed.source_refs)) parsed.source_refs = [];

